class Solution {
public:
    string solveEquation(string equation) {
        int x_coef = 0, constant = 0, sign = 1;
        int num = 0;
        bool has_x = false;
        for (int i = 0; i < equation.size(); i++) {
            char c = equation[i];
            if (c == '+' || c == '-') {
                constant += sign * num;
                num = 0;
                sign = (c == '+') ? 1 : -1;
            } else if (c == '=') {
                constant += sign * num;
                num = 0;
                sign = -1;
            } else if (c == 'x') {
                if (num == 0) num = 1;
                x_coef += sign * num;
                num = 0;
                has_x = true;
            } else {
                num = num * 10 + (c - '0');
            }
        }

        if (!has_x && x_coef == 0) {
            if (constant == 0) return "Infinite solutions";
            else return "No solution";
        }

        int value = constant / -x_coef;
        if (x_coef * value != constant) return "No solution";
        return "x=" + to_string(value);
    }
};
